#include<cstdio>
#include<algorithm>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e6+10;int n,m,a[N],cnt[N],t1[N],t2[N],ans2[N];
inline void add1(int p,const int &w){while(p<=n)t1[p]+=w,p+=(p&-p);}
inline void add2(int p,const int &w){while(p<=n)t2[p]+=w,p+=(p&-p);}
inline int qry1(int l,int r)
{
	int res=0;--l;while(r)res+=t1[r],r^=(r&-r);
	while(l)res-=t1[l],l^=(l&-l); return res;
}
inline int qry2(int l,int r)
{
	int res=0;--l;while(r)res+=t2[r],r^=(r&-r);
	while(l)res-=t2[l],l^=(l&-l); return res;
}
struct QQQ{int l,r,a,b,idx;inline bool operator<(const QQQ &Q)const{return (l>>9)==(Q.l>>9)?((l>>9)&1?r>Q.r:r<Q.r):l<Q.l;}}t[N];
inline void ins(const int &x){add1(x,1);if(!(cnt[x]++))add2(x,1);}
inline void del(const int &x){add1(x,-1);if(!(--cnt[x]))add2(x,-1);}
int main()
{
	n=read();m=read();rep(1,n,i)a[i]=read();
	rep(1,m,i)t[i].l=read(),t[i].r=read(),t[i].a=read(),t[i].b=read(),t[i].idx=i;
	std::sort(t+1,t+m+1); int L=t[1].l,R=t[1].l-1;
	rep(1,m,i)
	{
		while(R<t[i].r)ins(a[++R]);while(L>t[i].l)ins(a[--L]);
		while(R>t[i].r)del(a[R--]);while(L<t[i].l)del(a[L++]);
		ans2[t[i].idx]=qry2(t[i].a,t[i].b);
	}
	rep(1,m,i)printf("%d\n",ans2[i]);
}
